package com.samudhra.certificates.service;
import com.samudhra.certificates.entity.*; import com.samudhra.certificates.repository.UploadRepository; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.*; import org.springframework.stereotype.Service; import org.springframework.web.multipart.MultipartFile; import java.io.*; import java.nio.file.*; import java.util.*;
@Service public class StorageService { private static final Set<String> TYPES=Set.of("image/png","image/jpeg","image/svg+xml"); private final Path root; private final UploadRepository uploads; public StorageService(@Value("${app.upload-dir}") String directory,UploadRepository uploads)throws IOException{root=Paths.get(directory).toAbsolutePath().normalize();Files.createDirectories(root);this.uploads=uploads;}
 public Upload store(MultipartFile file,String purpose,User user)throws IOException {if(file.isEmpty()||!TYPES.contains(file.getContentType()))throw new IllegalArgumentException("Only PNG, JPG, JPEG, and SVG images are allowed");String ext=Optional.ofNullable(file.getOriginalFilename()).filter(n->n.contains(".")).map(n->n.substring(n.lastIndexOf('.'))).orElse(".png");String name=UUID.randomUUID()+ext;Files.copy(file.getInputStream(),root.resolve(name));Upload upload=new Upload();upload.setOrganization(user.getOrganization());upload.setUploadedBy(user);upload.setPurpose(purpose);upload.setStoredName(name);upload.setOriginalName(file.getOriginalFilename());upload.setContentType(file.getContentType());upload.setSize(file.getSize());upload.setUrl("/uploads/"+name);return uploads.save(upload);}}
